module.render:
const color = args.color || 'var(--accent-color)';
const numberStr = sections[0] ? sections[0].trim() : '';
const labelStr = sections[1] ? sections[1].trim() : '';
const captionStr = sections[2] ? sections[2].trim() : '';
let html = `\n\n<div class="mdp-mod-bignumber">`;
html += `<div class="bignumber-value" style="color: ${color};">${numberStr}</div>`;
if (labelStr) html += `<div class="bignumber-label">${labelStr}</div>`;
if (captionStr) html += `<div class="bignumber-caption">${captionStr}</div>`;
html += `</div>\n\n`;
return html;
